                }
                // After moving top, the bottom s boxes are still in src above k
                int first_bot = S.stacks[src][h + 1];
                dest1 = plan.dest[k];
                if (dest1 == src) dest1 = (src + 1) % M;
                S.move_block(first_bot, s, dest1);
            } else {
                // No split: move all to dest
                int dest = plan.dest[k];
                if (dest == src) dest = (src + 1) % M;
                S.move_block(S.stacks[src][h + 1], num_on_top, dest);
            }
        }
        S.carry_out(k);
    }
    return S.energy;
}

long long lookahead_energy(State S, int start_k, int W) {
    long long e0 = S.energy;
    int end_k = std::min(start_k + W, S.N);
    for (int k = start_k; k < end_k; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = greedy_best_dest(S, k);
            if (dest == src) dest = (src + 1) % S.M;
            S.move_block(S.stacks[src][h + 1], num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy - e0;
}

void beam_search(const std::vector<std::vector<int>>& initial_stacks,
                 int N, int M, Plan& result_plan, double time_limit) {
    const int BEAM_W = 12;
    const int LOOKAHEAD = 8;

    struct BeamNode {
        State state;
        int plan[MAX_N];
    };

    std::vector<BeamNode> beam(1);
    beam[0].state.init(N, M, initial_stacks);
    beam.reserve(BEAM_W);

    std::vector<BeamNode> candidates;
    candidates.reserve(BEAM_W * (M - 1) + BEAM_W);

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_limit) {
            auto& best = beam[0];
            for (int kk = k; kk < N; kk++) {
                best.plan[kk] = greedy_best_dest(best.state, kk);
                int src = best.state.box_stack[kk];
                int h = best.state.box_height[kk];
                int num_on_top = best.state.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int dest = best.plan[kk];
                    if (dest == src) dest = (src + 1) % M;
                    best.state.move_block(best.state.stacks[src][h + 1], num_on_top, dest);
                }
                best.state.carry_out(kk);
            }
            for (int i = 0; i < N; i++) result_plan.dest[i] = best.plan[i];
            memset(result_plan.split, 0, sizeof(result_plan.split));
            memset(result_plan.dest2, 0, sizeof(result_plan.dest2));
            return;
        }

        candidates.clear();

        for (auto& node : beam) {
            int src = node.state.box_stack[k];
            int h = node.state.box_height[k];
            int num_on_top = node.state.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                candidates.push_back(node);
                auto& cand = candidates.back();
                cand.plan[k] = src;
                cand.state.carry_out(k);
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    candidates.push_back(node);
                    auto& cand = candidates.back();
                    cand.plan[k] = d;
                    cand.state.move_block(cand.state.stacks[src][h + 1], num_on_top, d);
                    cand.state.carry_out(k);
                }
            }
        }

        if (candidates.empty()) break;

        std::vector<std::pair<long long, int>> scores(candidates.size());
        for (int i = 0; i < (int)candidates.size(); i++) {
            long long future = lookahead_energy(candidates[i].state, k + 1, LOOKAHEAD);
            scores[i] = {candidates[i].state.energy + future, i};
        }
        std::sort(scores.begin(), scores.end());

        beam.clear();
        int width = std::min(BEAM_W, (int)scores.size());
        for (int i = 0; i < width; i++) {
            beam.push_back(std::move(candidates[scores[i].second]));
        }
    }

    int best_idx = 0;
    for (int i = 1; i < (int)beam.size(); i++) {
        if (beam[i].state.energy < beam[best_idx].state.energy) best_idx = i;
    }
    for (int i = 0; i < N; i++) result_plan.dest[i] = beam[best_idx].plan[i];
    memset(result_plan.split, 0, sizeof(result_plan.split));
    memset(result_plan.dest2, 0, sizeof(result_plan.dest2));
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();
    RGen.seed_time();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
    }

    // Phase 1: Beam search for good initial plan (use 0.4s)
    Plan best_plan;
    beam_search(initial_stacks, N, M, best_plan, 0.40);
    long long best_energy = simulate_plan(initial_stacks, best_plan, N, M);

    // Phase 2: SA refinement with split mutations
    Plan current_plan;
    memcpy(&current_plan, &best_plan, sizeof(Plan));
    long long current_energy = best_energy;

    const double SA_END_TIME = 1.75;
    double sa_start = elapsed_seconds();
    double sa_budget = SA_END_TIME - sa_start;
    double T_init = 8.0;
    double T_final = 0.5;
    double current_T = T_init;

    while (true) {
        double now = elapsed_seconds();
        if (now >= SA_END_TIME) break;
        double progress = (now - sa_start) / sa_budget;
        current_T = T_init * std::pow(T_final / T_init, std::min(1.0, progress));

        for (int batch = 0; batch < 128; batch++) {
            // Choose mutation type
            int mut_type = RGen.an_int(0, 99);

            // Save old state for rollback
            int idx1, old_dest1, old_split1, old_dest2_1;
            int idx2 = -1, old_dest2 = 0, old_split2 = 0, old_dest2_2 = 0;

            // Bias toward earlier indices
            idx1 = std::min(N - 1, (int)(N * (1.0 - std::sqrt(RGen.a_double(0, 1)))));
            old_dest1 = current_plan.dest[idx1];
            old_split1 = current_plan.split[idx1];
            old_dest2_1 = current_plan.dest2[idx1];

            if (mut_type < 50) {
                // Mutate primary destination
                current_plan.dest[idx1] = RGen.an_int(0, M - 1);
            } else if (mut_type < 70) {
                // Toggle or change split
                if (current_plan.split[idx1] == 0) {
                    // Add a split: random split point 1..19 (will be clamped during sim)
                    current_plan.split[idx1] = RGen.an_int(1, 15);
                    current_plan.dest2[idx1] = RGen.an_int(0, M - 1);
                } else {
                    // Remove split
                    current_plan.split[idx1] = 0;
                }
            } else if (mut_type < 85) {
                // Change split point
                if (current_plan.split[idx1] > 0) {
                    current_plan.split[idx1] = RGen.an_int(1, 15);
                } else {
                    current_plan.dest[idx1] = RGen.an_int(0, M - 1);
                }
            } else if (mut_type < 95) {
                // Change dest2
                if (current_plan.split[idx1] > 0) {
                    current_plan.dest2[idx1] = RGen.an_int(0, M - 1);
                } else {
                    current_plan.dest[idx1] = RGen.an_int(0, M - 1);
                }
            } else {
                // 2-point mutation on dest
                current_plan.dest[idx1] = RGen.an_int(0, M - 1);
                if (idx1 + 1 < N) {
                    idx2 = idx1 + 1;
                    old_dest2 = current_plan.dest[idx2];
                    old_split2 = current_plan.split[idx2];
                    old_dest2_2 = current_plan.dest2[idx2];
                    current_plan.dest[idx2] = RGen.an_int(0, M - 1);
                }
            }

            long long new_energy = simulate_plan(initial_stacks, current_plan, N, M);

            long long delta = new_energy - current_energy;
            if (delta <= 0 || RGen.a_double(0, 1) < std::exp(-(double)delta / current_T)) {
                current_energy = new_energy;
                if (new_energy < best_energy) {
                    best_energy = new_energy;
                    memcpy(&best_plan, &current_plan, sizeof(Plan));
                }
            } else {
                // Rollback
                current_plan.dest[idx1] = old_dest1;
                current_plan.split[idx1] = old_split1;
                current_plan.dest2[idx1] = old_dest2_1;
                if (idx2 >= 0) {
                    current_plan.dest[idx2] = old_dest2;
                    current_plan.split[idx2] = old_split2;
                    current_plan.dest2[idx2] = old_dest2_2;
                }
            }
        }
    }

    // Output using best_plan
    {
        State S;
        S.init(N, M, initial_stacks);
        for (int k = 0; k < N; k++) {
            int src = S.box_stack[k];
            int h = S.box_height[k];
            int num_on_top = S.stack_size[src] - 1 - h;
            if (num_on_top > 0) {
                int s = best_plan.split[k];
                if (s > 0 && s < num_on_top) {
                    // Split move
                    int top_count = num_on_top - s;
                    int dest2 = best_plan.dest2[k];
                    if (dest2 == src) dest2 = (src + 1) % M;
                    int first_top = S.stacks[src][h + 1 + s];
                    std::cout << (first_top + 1) << " " << (dest2 + 1) << "\n";
                    S.move_block(first_top, top_count, dest2);
                    // Bottom portion
                    int first_bot = S.stacks[src][h + 1];
                    int dest1 = best_plan.dest[k];
                    if (dest1 == src) dest1 = (src + 1) % M;
                    std::cout << (first_bot + 1) << " " << (dest1 + 1) << "\n";
                    S.move_block(first_bot, s, dest1);
                } else {
                    // No split
                    int dest = best_plan.dest[k];
                    if (dest == src) dest = (src + 1) % M;
                    int first_box = S.stacks[src][h + 1];
                    std::cout << (first_box + 1) << " " << (dest + 1) << "\n";
                    S.move_block(first_box, num_on_top, dest);
                }
            }
            std::cout << (k + 1) << " 0\n";
            S.carry_out(k);
        }
    }

    return 0;
}
